import { encrypt, decrypt } from 'react-native-aes-crypto';
import { ENCRYPTION_KEY } from './config';

export async function secureData(data) {
  try {
    return await encrypt(JSON.stringify(data), ENCRYPTION_KEY);
  } catch (error) {
    console.error('Error encrypting data:', error);
    throw error;
  }
}

export async function unsecureData(encryptedData) {
  try {
    const decryptedData = await decrypt(encryptedData, ENCRYPTION_KEY);
    return JSON.parse(decryptedData);
  } catch (error) {
    console.error('Error decrypting data:', error);
    throw error;
  }
}

